<script setup>
import { Link, router, useForm, usePage } from '@inertiajs/vue3';
import { computed, ref } from 'vue';
import PortalLayout from '../../Layouts/PortalLayout.vue';
import SectionTitle from '../../Components/SectionTitle.vue';
import { statusLabel } from '../../lib/status';

const props = defineProps({ event: Object, category: Object, entries: Array, pdams: Array });
const page = usePage();
const activeSection = ref('players');
const openPdam = ref(null);
const flash = computed(() => page.props.flash || {});
const minMembers = computed(() => props.category?.min_members || 1);
const maxMembers = computed(() => props.category?.max_members ?? null);
const maxTeams = computed(() => props.category?.max_teams_per_pd || 1);
const maxOfficials = computed(() => props.category?.max_officials_per_pd || 0);
const officialRoles = computed(() => props.category?.official_roles || []);
const teamRevisionEntry = computed(() => props.entries.find((entry) => entry.teams.some((team) => team.editable)));
const editableEntry = computed(() => teamRevisionEntry.value || props.entries.find((entry) => ['draft', 'revision_required'].includes(entry.verification_status) || (entry.verification_status === 'cancelled' && props.event.registration_open)));
const teamScopedRevision = computed(() => !!teamRevisionEntry.value && teamRevisionEntry.value.verification_status === 'pending');
const lockedEntry = computed(() => props.entries.find((entry) => ['verified', 'rejected'].includes(entry.verification_status) || (entry.verification_status === 'cancelled' && !props.event.registration_open) || (entry.verification_status === 'pending' && !entry.teams.some((team) => team.editable))));
const registeredTeams = computed(() => editableEntry.value?.teams.length || lockedEntry.value?.teams.length || 0);
const remainingTeams = computed(() => Math.max(0, maxTeams.value - registeredTeams.value));
const playerDocuments = { photo: 'Foto 3×4', registration_form: 'Form Pendaftaran', identity_card: 'KTP Pemain', pension_card: 'Kartu DAPENMA PAMSI / Dana Pensiun Lainnya', employee_decree: 'SK Karyawan Tetap' };
const officialDocuments = { photo: 'Foto 3×4', identity_card: 'KTP Official' };
const pdamLabel = (pdam) => [pdam.name, pdam.city, pdam.province].filter(Boolean).join(' · ');
const blankMember = () => ({ id: null, name: '', pdam_id: null, pdam_search: '', identity_type: 'nik', identity_number: '', documents: {} });
const normalizeMember = (member) => ({ ...blankMember(), ...member, pdam_search: member.pdam_name || '', documents: {}, existing_documents: member.documents || [] });
const blankMembers = () => Array.from({ length: minMembers.value }, blankMember);
const initialTeams = editableEntry.value?.teams?.length ? editableEntry.value.teams.filter((team) => !teamScopedRevision.value || team.editable).map((team) => ({ id: team.id, team_no: team.team_no, verification_note: team.verification_note, members: team.members.map(normalizeMember) })) : [{ id: null, team_no: 1, members: blankMembers() }];
const initialOfficials = teamScopedRevision.value ? [] : editableEntry.value?.officials?.map((official) => ({ ...normalizeMember(official), role: official.role || officialRoles.value[0] || '' })) || [];
const form = useForm({ intent: 'draft', teams: initialTeams, officials: initialOfficials });
const memberError = (teamIndex, memberIndex, field) => form.errors[`teams.${teamIndex}.members.${memberIndex}.${field}`];
const officialError = (index, field) => form.errors[`officials.${index}.${field}`];
const hasDocument = (member, key) => !!member.documents[key] || member.existing_documents?.includes(key);
const setFile = (member, key, event) => { member.documents[key] = event.target.files?.[0] || null; };
const documentLabel = (key) => ({ photo: 'Foto 3×4', registration_form: 'Form Pendaftaran', identity_card: 'KTP', pension_card: 'Kartu Pensiun', employee_decree: 'SK Karyawan Tetap' }[key] || key);
const filteredPdams = (member) => { const search = member.pdam_search.trim().toLowerCase(); return props.pdams.filter((pdam) => !search || pdamLabel(pdam).toLowerCase().includes(search)).slice(0, 30); };
const selectPdam = (member, pdam) => { member.pdam_id = pdam.id; member.pdam_search = pdamLabel(pdam); openPdam.value = null; };
const addMember = (team) => { if (maxMembers.value === null || team.members.length < maxMembers.value) team.members.push(blankMember()); };
const removeMember = (team, index) => { if (team.members.length > minMembers.value) team.members.splice(index, 1); };
const addTeam = () => { if (!teamScopedRevision.value && form.teams.length < maxTeams.value) form.teams.push({ id: null, team_no: form.teams.length + 1, members: blankMembers() }); };
const removeTeam = (index) => { if (form.teams.length > 1) form.teams.splice(index, 1); };
const addOfficial = () => { if (form.officials.length < maxOfficials.value) form.officials.push({ ...blankMember(), role: officialRoles.value[0] || '' }); };
const submit = (intent) => { form.intent = intent; form.post(`/pd/events/${props.event.code}/entries`, { preserveScroll: true, forceFormData: true }); };
const cancel = (id) => { if (confirm('Batalkan pendaftaran ini?')) router.delete(`/pd/entries/${id}`, { preserveScroll: true }); };
</script>

<template>
  <PortalLayout portal="pd">
    <div class="page-head"><SectionTitle eyebrow="Pendaftaran Cabor" :title="event.name" :meta="`${event.sport} · ${category?.name || 'Umum'}`" /><Link href="/pd/dashboard" class="back">← Kembali ke Dashboard</Link></div>
    <div v-if="flash.success" class="flash ok">{{ flash.success }}</div><div v-if="flash.error" class="flash err">{{ flash.error }}</div>

    <section class="competition-rules portal-card"><header><div><span>Aturan Pendaftaran</span><h3>{{ category?.name }}</h3></div><small>Ketentuan ini dikunci saat kompetisi dipublikasikan.</small></header><div class="rule-grid"><article><span>Format Pertandingan</span><strong>{{ event.format_label }}</strong><small>Format pelaksanaan ditetapkan panitia.</small></article><article><span>Kuota Tim PD</span><strong>{{ registeredTeams }} dari {{ maxTeams }} tim</strong><small>{{ remainingTeams ? `Masih dapat menambahkan ${remainingTeams} tim sebelum diajukan.` : 'Kuota tim telah terpakai.' }}</small></article><article><span>Komposisi Tim</span><strong>{{ maxMembers === null ? `Minimal ${minMembers} pemain` : minMembers === maxMembers ? `${minMembers} pemain per tim` : `${minMembers}–${maxMembers} pemain per tim` }}</strong><small>Jumlah pemain tidak dapat melewati ketentuan.</small></article><article><span>Official</span><strong>Maksimal {{ maxOfficials }} orang</strong><small>{{ category?.official_can_compete ? 'Official boleh didaftarkan sebagai pemain.' : 'Official tidak boleh merangkap sebagai pemain.' }}</small></article></div></section>

    <form v-if="(event.registration_open || editableEntry?.verification_status === 'revision_required' || teamScopedRevision) && !lockedEntry" class="registration-shell portal-card" @submit.prevent>
      <header class="form-head"><div><span>{{ teamScopedRevision ? 'PERBAIKAN TIM' : 'FORM REGISTRASI PD' }}</span><h3>{{ teamScopedRevision ? 'Lengkapi Perbaikan yang Diminta' : editableEntry ? 'Perbarui Data Peserta' : 'Lengkapi Data Peserta' }}</h3><p>{{ teamScopedRevision ? 'Hanya tim yang diminta perbaikan yang dapat diubah. Tim lain tetap terkunci.' : 'Draft dapat disimpan tanpa lampiran lengkap. Semua dokumen wajib sebelum diajukan.' }}</p></div><div class="progress"><b>{{ form.teams.reduce((sum, team) => sum + team.members.length, 0) }}</b><small>Pemain</small></div></header>
      <nav class="form-tabs" aria-label="Bagian form"><button type="button" :class="{ active: activeSection === 'players' }" @click="activeSection = 'players'">Pemain <span>{{ form.teams.reduce((sum, team) => sum + team.members.length, 0) }}</span></button><button v-if="!teamScopedRevision" type="button" :class="{ active: activeSection === 'officials' }" @click="activeSection = 'officials'">Official <span>{{ form.officials.length }}</span></button></nav>

      <div v-show="activeSection === 'players'" class="section-stack">
        <article v-for="(team, teamIndex) in form.teams" :key="team.id || teamIndex" class="team-card"><header><div><small>UNIT PESERTA</small><h4>Tim #{{ team.team_no || teamIndex + 1 }}</h4></div><button v-if="!teamScopedRevision && form.teams.length > 1" type="button" class="text-danger" @click="removeTeam(teamIndex)">Hapus Tim</button></header><p v-if="team.verification_note" class="team-feedback"><strong>Catatan Panitia</strong>{{ team.verification_note }}</p>
          <div v-for="(member, memberIndex) in team.members" :key="member.id || memberIndex" class="person-card">
            <div class="person-title"><b>{{ memberIndex + 1 }}</b><div><strong>Pemain {{ memberIndex + 1 }}</strong><small>Identitas dan dokumen pemain</small></div><button v-if="team.members.length > minMembers" type="button" class="text-danger" @click="removeMember(team, memberIndex)">Hapus</button></div>
            <div class="identity-grid"><label class="portal-field"><span>Nama Lengkap</span><input v-model="member.name" maxlength="120"><small v-if="memberError(teamIndex, memberIndex, 'name')" class="err">{{ memberError(teamIndex, memberIndex, 'name') }}</small></label><div class="portal-field pdam-field"><span>Asal PDAM</span><input v-model="member.pdam_search" type="search" autocomplete="off" placeholder="Cari nama PDAM, kota, atau provinsi" @focus="openPdam = `${teamIndex}-${memberIndex}`" @input="member.pdam_id = null; openPdam = `${teamIndex}-${memberIndex}`"><div v-if="openPdam === `${teamIndex}-${memberIndex}`" class="pdam-dropdown"><button v-for="pdam in filteredPdams(member)" :key="pdam.id" type="button" @mousedown.prevent="selectPdam(member, pdam)"><strong>{{ pdam.name }}</strong><small>{{ [pdam.city, pdam.province].filter(Boolean).join(' · ') }}</small></button><p v-if="!filteredPdams(member).length">PDAM tidak ditemukan.</p></div><small v-if="memberError(teamIndex, memberIndex, 'pdam_id')" class="err">{{ memberError(teamIndex, memberIndex, 'pdam_id') }}</small></div><label class="portal-field"><span>Jenis Identitas</span><select v-model="member.identity_type"><option value="nik">NIK</option><option value="kta">KTA</option></select></label><label class="portal-field"><span>Nomor NIK/KTA</span><input v-model="member.identity_number" maxlength="50" placeholder="Nomor tanpa spasi"><small v-if="memberError(teamIndex, memberIndex, 'identity_number')" class="err">{{ memberError(teamIndex, memberIndex, 'identity_number') }}</small></label></div>
            <div class="documents"><div class="documents-head"><strong>Kelengkapan Pemain</strong><small>JPG, PNG, atau PDF · maksimal 5 MB</small></div><label v-for="(label, key) in playerDocuments" :key="key" :class="['upload-row', { ready: hasDocument(member, key) }]"><span><b>{{ hasDocument(member, key) ? '✓' : '○' }}</b>{{ label }}</span><input type="file" accept=".jpg,.jpeg,.png,.pdf" @change="setFile(member, key, $event)"><em>{{ member.documents[key]?.name || (member.existing_documents?.includes(key) ? 'Sudah tersimpan' : 'Pilih file') }}</em><small v-if="memberError(teamIndex, memberIndex, `documents.${key}`)" class="err">{{ memberError(teamIndex, memberIndex, `documents.${key}`) }}</small></label></div>
          </div>
          <button v-if="maxMembers === null || team.members.length < maxMembers" type="button" class="portal-button secondary" @click="addMember(team)">+ Tambah Pemain</button>
        </article>
        <div v-if="!teamScopedRevision" class="team-capacity"><button v-if="form.teams.length < maxTeams" type="button" class="portal-button secondary" @click="addTeam">Tambah Tim {{ form.teams.length + 1 }}</button><span>{{ form.teams.length < maxTeams ? `Tersisa ${maxTeams - form.teams.length} slot tim.` : `Batas ${maxTeams} tim telah tercapai.` }}</span></div><small v-if="form.errors.teams" class="err">{{ form.errors.teams }}</small>
      </div>

      <div v-show="activeSection === 'officials'" class="section-stack"><div :class="['policy-alert', category?.official_can_compete ? 'allowed' : 'blocked']"><strong>{{ category?.official_can_compete ? 'Official boleh merangkap pemain' : 'Official dilarang merangkap pemain' }}</strong><span>Pemeriksaan memakai NIK/KTA pada seluruh registrasi aktif PD.</span></div>
        <article v-for="(official, index) in form.officials" :key="official.id || index" class="person-card"><div class="person-title"><b>O</b><div><strong>Official {{ index + 1 }}</strong><small>Data official dipisahkan dari roster pemain</small></div><button type="button" class="text-danger" @click="form.officials.splice(index, 1)">Hapus</button></div><div class="identity-grid official"><label class="portal-field"><span>Nama Lengkap</span><input v-model="official.name" maxlength="120"></label><label class="portal-field"><span>Peran</span><select v-model="official.role"><option v-for="role in officialRoles" :key="role" :value="role">{{ role }}</option></select></label><label class="portal-field"><span>Jenis Identitas</span><select v-model="official.identity_type"><option value="nik">NIK</option><option value="kta">KTA</option></select></label><label class="portal-field"><span>Nomor NIK/KTA</span><input v-model="official.identity_number" maxlength="50"></label></div><div class="documents"><div class="documents-head"><strong>Kelengkapan Official</strong><small>Foto dan KTP wajib saat diajukan</small></div><label v-for="(label, key) in officialDocuments" :key="key" :class="['upload-row', { ready: hasDocument(official, key) }]"><span><b>{{ hasDocument(official, key) ? '✓' : '○' }}</b>{{ label }}</span><input type="file" accept=".jpg,.jpeg,.png,.pdf" @change="setFile(official, key, $event)"><em>{{ official.documents[key]?.name || (official.existing_documents?.includes(key) ? 'Sudah tersimpan' : 'Pilih file') }}</em><small v-if="officialError(index, `documents.${key}`)" class="err">{{ officialError(index, `documents.${key}`) }}</small></label></div><p v-if="official.playing_sports?.length" class="playing">Juga bermain: {{ official.playing_sports.join(', ') }}</p></article>
        <button v-if="form.officials.length < maxOfficials" type="button" class="portal-button secondary" @click="addOfficial">+ Tambah Official</button><p v-if="maxOfficials === 0" class="empty-note">Regulasi cabor tidak menyediakan kuota official.</p><small v-if="form.errors.officials" class="err">{{ form.errors.officials }}</small>
      </div>
      <footer class="form-actions"><button v-if="!teamScopedRevision" type="button" class="portal-button secondary" :disabled="form.processing" @click="submit('draft')">Simpan Draft</button><button type="button" class="portal-button primary" :disabled="form.processing" @click="submit('submit')">{{ teamScopedRevision ? 'Kirim Ulang Perbaikan' : 'Ajukan Pendaftaran' }}</button></footer>
    </form>

    <div v-if="lockedEntry" class="locked-notice"><strong>Pendaftaran {{ statusLabel(lockedEntry.verification_status).toLowerCase() }}</strong><span>Data dikunci selama proses verifikasi. Panitia akan membuka perbaikan bila ada data yang perlu diperbarui.</span><span v-if="remainingTeams">Kuota masih menyisakan {{ remainingTeams }} tim. Penambahan tim tersedia setelah panitia membuka <b>Perbaikan Roster</b> tingkat pendaftaran.</span></div>
    <section class="entry-list portal-card"><div class="portal-card-head"><h3>Detail Roster Diajukan</h3></div><div class="roster-records"><article v-for="entry in entries" :key="entry.id" class="roster-record"><header><div><strong>{{ entry.display_name }}</strong><small>{{ entry.teams.reduce((sum, team) => sum + team.members.length, 0) }} pemain · {{ entry.officials.length }} official</small></div><span :class="['tag', entry.verification_status]">{{ statusLabel(entry.verification_status) }}</span></header><p v-if="entry.verification_note" class="entry-note">{{ entry.verification_note }}</p><section v-for="team in entry.teams" :key="team.id" :class="['roster-team', { attention: ['revision_required','rejected'].includes(team.status) }]"><div class="roster-team-head"><strong>{{ team.label }}</strong><span>Status tim: {{ statusLabel(team.status) }}</span></div><p v-if="team.verification_note" class="entry-note"><strong>Catatan tim</strong>{{ team.verification_note }}</p><details v-for="member in team.members" :key="member.id" class="roster-person" :open="member.verification_status === 'revision_required'"><summary><span><b>{{ member.name }}</b><small>{{ member.pdam_name || 'PDAM belum diisi' }} · {{ member.identity_type?.toUpperCase() }} {{ member.identity_number }}</small></span><span :class="['tag', member.verification_status]">{{ statusLabel(member.verification_status) }}</span></summary><div><p v-if="member.verification_note" class="entry-note">{{ member.verification_note }}</p><nav><a v-for="document in member.document_links" :key="document.key" :href="document.url" target="_blank" rel="noopener">{{ documentLabel(document.key) }}</a></nav><small>Diperbarui {{ member.updated_at || '—' }}</small></div></details></section><section v-if="entry.officials.length" class="roster-officials"><strong>Official</strong><details v-for="official in entry.officials" :key="official.id"><summary>{{ official.name }} · {{ official.role.replaceAll('_', ' ') }}</summary><nav><a v-for="document in official.document_links" :key="document.key" :href="document.url" target="_blank" rel="noopener">{{ documentLabel(document.key) }}</a></nav></details></section><footer><button v-if="['draft','pending','revision_required','rejected'].includes(entry.verification_status)" class="text-danger" @click="cancel(entry.id)">Batalkan Pendaftaran</button></footer></article><p v-if="!entries.length" class="empty-note">Belum ada pendaftaran.</p></div></section>
  </PortalLayout>
</template>

<style scoped>
.page-head{padding:8px 0 18px}.back{display:inline-flex;margin-top:8px;color:var(--portal-primary);font-size:12px;font-weight:800;text-decoration:none}.flash,.locked-notice{margin-bottom:14px;padding:13px 16px;border:1px solid;border-radius:10px}.flash.ok{color:#087365;background:#eefaf6;border-color:#b9e3d6}.flash.err,.err{color:var(--portal-danger)}.rules-strip{display:grid;grid-template-columns:repeat(4,1fr);gap:1px;margin-bottom:18px;padding:0;overflow:hidden}.rules-strip div{display:grid;gap:4px;padding:16px;background:#fff}.rules-strip small,.form-head span,.team-card header small{color:#73838d;font-size:10px;font-weight:800;letter-spacing:.1em;text-transform:uppercase}.rules-strip strong{color:#213746}.rules-strip p{grid-column:1/-1;margin:0;padding:11px 16px;font-size:11px;font-weight:700}.allowed{color:#087365;background:#eefaf6}.blocked{color:#a1432e;background:#fff4ef}.registration-shell,.entry-list{margin-bottom:18px;padding:0;overflow:hidden}.form-head{display:flex;justify-content:space-between;gap:20px;padding:22px 24px;background:linear-gradient(120deg,#f8fafb,#edf4f7)}.form-head h3{margin:4px 0;color:#173346;font-size:22px}.form-head p{margin:0;color:#687985;font-size:12px}.progress{display:grid;min-width:82px;padding:10px;text-align:center;background:#fff;border:1px solid #d9e4e9;border-radius:12px}.progress b{color:var(--portal-primary);font-size:24px}.progress small{color:#687985}.form-tabs{display:flex;padding:0 24px;border-bottom:1px solid #dce6ea}.form-tabs button{padding:15px 18px;color:#657680;background:none;border:0;border-bottom:3px solid transparent;font-weight:800;cursor:pointer}.form-tabs button.active{color:var(--portal-primary);border-color:var(--portal-primary)}.form-tabs span{margin-left:7px;padding:3px 7px;background:#eaf1f5;border-radius:999px;font-size:10px}.section-stack{display:grid;gap:16px;padding:22px 24px}.team-card,.person-card{display:grid;gap:14px;padding:16px;border:1px solid #dce6ea;border-radius:12px;background:#fbfcfd}.team-card>header,.person-title,.documents-head{display:flex;align-items:center;justify-content:space-between;gap:12px}.team-card h4{margin:2px 0 0;color:#173346}.person-card{background:#fff}.person-title b{display:grid;place-items:center;width:34px;height:34px;color:#fff;background:#1946a3;border-radius:10px}.person-title div{display:grid;flex:1}.person-title small,.documents-head small{color:#758590;font-size:11px}.identity-grid{display:grid;grid-template-columns:1.4fr .55fr 1fr;gap:12px}.identity-grid.official{grid-template-columns:1.3fr 1fr .55fr 1fr}.documents{display:grid;gap:8px;padding:13px;background:#f5f8fa;border-radius:10px}.upload-row{display:grid;grid-template-columns:minmax(230px,1fr) auto;gap:3px 12px;align-items:center;padding:10px 12px;background:#fff;border:1px solid #dde6ea;border-radius:8px;cursor:pointer}.upload-row.ready{border-color:#afd9cd;background:#f3fbf8}.upload-row span{display:flex;gap:9px;align-items:center;color:#415765;font-size:12px;font-weight:750}.upload-row b{color:#8b9aa3}.upload-row.ready b{color:#087365}.upload-row input{position:absolute;width:1px;height:1px;opacity:0}.upload-row em{color:var(--portal-primary);font-size:11px;font-style:normal;font-weight:800}.upload-row .err{grid-column:1/-1}.policy-alert{display:grid;gap:3px;padding:13px 15px;border-radius:10px}.policy-alert span{font-size:11px}.playing{margin:0;padding:9px 11px;color:#1946a3;background:#eef4fb;border-radius:8px;font-size:11px}.form-actions{display:flex;justify-content:flex-end;gap:10px;padding:18px 24px;background:#f7f9fa;border-top:1px solid #dce6ea}.text-danger{color:var(--portal-danger);background:none;border:0;font-size:11px;font-weight:800;cursor:pointer}.locked-notice{display:grid;gap:4px;color:#655000;background:#fff9e8;border-color:#eedb94}.entry-list .portal-card-head{padding:18px 20px}.tag{display:inline-flex;padding:5px 9px;border-radius:999px;background:#edf2f5;font-size:10px;font-weight:800}.empty-note{padding:18px;color:#758590;text-align:c